import { motion } from "framer-motion";
import { useEffect, useRef } from "react";

const BackgroundEffects = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  // Canvas wave animation
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d");
    if (!ctx) return;

    let width = (canvas.width = window.innerWidth);
    let height = (canvas.height = window.innerHeight);
    let t = 0;

    const resize = () => {
      width = canvas.width = window.innerWidth;
      height = canvas.height = window.innerHeight;
    };

    window.addEventListener("resize", resize);

    function animate() {
      ctx.clearRect(0, 0, width, height);

      // gradient background fade
      const gradient = ctx.createLinearGradient(0, 0, width, height);
      gradient.addColorStop(0, "rgba(232, 247, 239, 0.4)");
      gradient.addColorStop(1, "rgba(195, 234, 212, 0.4)");
      ctx.fillStyle = gradient;
      ctx.fillRect(0, 0, width, height);

      // flowing waves (soft orange lines)
      for (let i = 0; i < 3; i++) {
        ctx.beginPath();
        for (let x = 0; x < width; x++) {
          const y =
            Math.sin(x * 0.005 + t + i) * 20 +
            Math.sin(x * 0.001 + t * 0.5) * 10 +
            height / 2 +
            (i - 1) * 80;
          ctx.lineTo(x, y);
        }
        ctx.strokeStyle = `rgba(${45 - i * 10}, ${170 - i * 20}, ${96 + i * 10}, 0.15)`;
        ctx.lineWidth = 1.5 + i * 0.5;
        ctx.stroke();
      }

      t += 0.015;
      requestAnimationFrame(animate);
    }

    animate();
    return () => window.removeEventListener("resize", resize);
  }, []);

  return (
    <div className="fixed inset-0 -z-10 overflow-hidden pointer-events-none">
      {/* Flowing canvas background */}
      <canvas ref={canvasRef} className="absolute inset-0" />

      {/* Soft moving color gradients */}
      <motion.div
        className="absolute w-[700px] h-[700px] rounded-full bg-gradient-to-br from-accent-300/30 to-accent-500/30 blur-3xl"
        animate={{
          x: [0, 50, -50, 0],
          y: [0, -30, 30, 0],
          rotate: [0, 15, -15, 0],
        }}
        transition={{ duration: 30, repeat: Infinity, ease: "easeInOut" }}
        style={{ top: "10%", left: "10%" }}
      />

      <motion.div
        className="absolute w-[500px] h-[500px] rounded-full bg-gradient-to-tr from-accent-200/25 to-accent-400/25 blur-3xl"
        animate={{
          x: [0, -40, 40, 0],
          y: [0, 20, -20, 0],
          rotate: [0, -10, 10, 0],
        }}
        transition={{ duration: 35, repeat: Infinity, ease: "easeInOut" }}
        style={{ bottom: "10%", right: "10%" }}
      />

      {/* Subtle geometric outlines in bright theme colors */}
      <motion.div
        className="absolute border border-accent-300/20 rounded-full w-[300px] h-[300px]"
        style={{ top: "15%", right: "20%" }}
        animate={{
          rotate: [0, 360],
          scale: [1, 1.1, 1],
          opacity: [0.1, 0.3, 0.1],
        }}
        transition={{ duration: 50, repeat: Infinity, ease: "linear" }}
      />

      <motion.div
        className="absolute border border-primary-300/20 rounded-full w-[200px] h-[200px]"
        style={{ bottom: "20%", left: "15%" }}
        animate={{
          rotate: [0, -360],
          scale: [1, 1.2, 1],
          opacity: [0.1, 0.25, 0.1],
        }}
        transition={{ duration: 45, repeat: Infinity, ease: "linear" }}
      />

      <motion.div
        className="absolute border border-accent-400/20 rounded-full w-[400px] h-[400px]"
        style={{ top: "40%", left: "45%" }}
        animate={{
          rotate: [0, 180, 360],
          opacity: [0.05, 0.15, 0.05],
        }}
        transition={{ duration: 60, repeat: Infinity, ease: "linear" }}
      />
    </div>
  );
};

export default BackgroundEffects;

