.chatbot-button {
  position: fixed;
  bottom: 30px;
  right: 30px;
  width: 70px;
  height: 70px;
  border-radius: 50%;
  background: linear-gradient(135deg, #0d9488, #1e3a8a);
  color: white;
  border: none;
  font-size: 28px;
  cursor: pointer;
  box-shadow: 0 6px 14px rgba(13, 148, 136, 0.35);
  transition: all 0.3s ease-in-out;
  z-index: 999;
  display: flex;
  align-items: center;
  justify-content: center;
  font-weight: bold;
}

.chatbot-button:hover {
  transform: scale(1.1) rotate(10deg);
  box-shadow: 0 8px 18px rgba(30, 58, 138, 0.4);
}

.chatbot-button:focus {
  outline: 2px solid #14b8a6;
  outline-offset: 3px;
}

