  border-radius: 16px;
  box-shadow: 0 8px 24px rgba(0, 0, 0, 0.15);
  font-family: "Inter", sans-serif;
  color: var(--dark-grey);
}

.chatbot-header {
  background: linear-gradient(90deg, var(--brand-teal), var(--brand-navy));
  color: var(--white);
  font-weight: 600;
  padding: 1rem;
