import { useRef, useMemo } from 'react';
import { useFrame } from '@react-three/fiber';
import { Sphere, Line, Text } from '@react-three/drei';
import { Mesh, Vector3 } from 'three';

export const Globe3D = () => {
  const globeRef = useRef<Mesh>(null);

  useFrame(() => {
    if (globeRef.current) {
      globeRef.current.rotation.y += 0.002;
    }
  });

  // Pin points for Asia and Europe
  const pinPoints = useMemo(() => [
    {
      position: new Vector3(1.2, 0.6, 0.5), // Asia
      label: "Asia",
      color: "#ff6b35"
    },
    {
      position: new Vector3(-0.4, 0.8, 1.2), // Europe
      label: "Europe",
      color: "#00d4ff"
    },
  ], []);

  // Trade routes connecting Asia and Europe
  const routes = useMemo(() => [
    {
      start: new Vector3(1.2, 0.6, 0.5), // Asia
      end: new Vector3(-0.4, 0.8, 1.2), // Europe
      color: "#00ff88"
    },
  ], []);

  return (
    <group>
      {/* Main Globe - Realistic Earth colors */}
      <Sphere ref={globeRef} args={[1.5, 64, 64]}>
        <meshStandardMaterial
          color="#2a5c8f"
          metalness={0.3}
          roughness={0.7}
          wireframe={false}
          opacity={1}
        />
      </Sphere>

      {/* Ocean overlay with blue tint */}
      <Sphere args={[1.51, 64, 64]}>
        <meshStandardMaterial 
          color="#1e4d7a" 
          opacity={0.3} 
          transparent={true}
          wireframe={true}
        />
      </Sphere>

      {/* Asia continent highlight (light golden) */}
      <Sphere args={[1.52, 32, 32]} position={[0.3, 0.1, 0]} scale={[0.8, 0.7, 0.6]}>
        <meshBasicMaterial 
          color="#FFD700" 
          opacity={0.25} 
          transparent={true} 
          wireframe={false}
        />
      </Sphere>

      {/* Europe continent highlight (light golden) */}
      <Sphere args={[1.52, 32, 32]} position={[-0.2, 0.2, 0.3]} scale={[0.4, 0.35, 0.3]}>
        <meshBasicMaterial 
          color="#FFD700" 
          opacity={0.25} 
          transparent={true} 
          wireframe={false}
        />
      </Sphere>

      {/* Atmosphere glow */}
      <Sphere args={[1.6, 64, 64]}>
        <meshBasicMaterial 
          color="#87ceeb" 
          opacity={0.1} 
          transparent={true} 
          side={1}
        />
      </Sphere>

      {/* Trade routes */}
      {routes.map((route, i) => (
        <Line
          key={i}
          points={[route.start, route.end]}
          color={route.color}
          lineWidth={3}
          opacity={0.8}
          transparent={true}
          dashed={true}
          dashSize={0.1}
          gapSize={0.05}
        />
      ))}

      {/* Pin points for Asia and Europe */}
      {pinPoints.map((pin, i) => (
        <group key={i}>
          {/* Pin marker */}
          <mesh position={pin.position}>
            <cylinderGeometry args={[0.02, 0.06, 0.3, 8]} />
            <meshStandardMaterial
              color={pin.color}
              emissive={pin.color}
              emissiveIntensity={0.8}
            />
          </mesh>

          {/* Pin top sphere */}
          <mesh position={[pin.position.x, pin.position.y + 0.15, pin.position.z]}>
            <sphereGeometry args={[0.08, 16, 16]} />
            <meshStandardMaterial
              color={pin.color}
              emissive={pin.color}
              emissiveIntensity={1}
            />
          </mesh>

          {/* Pulsing ring around pin */}
          <mesh position={pin.position} rotation={[Math.PI / 2, 0, 0]}>
            <ringGeometry args={[0.1, 0.15, 32]} />
            <meshBasicMaterial
              color={pin.color}
              opacity={0.5}
              transparent={true}
            />
          </mesh>
        </group>
      ))}

      {/* Continent Labels */}
      <Text
        position={[1.4, 0.7, 0.6]}
        fontSize={0.15}
        color="#FFD700"
        fontWeight="bold"
        outlineWidth={0.02}
        outlineColor="#000000"
      >
        ASIA
      </Text>

      <Text
        position={[-0.5, 0.9, 1.3]}
        fontSize={0.15}
        color="#FFD700"
        fontWeight="bold"
        outlineWidth={0.02}
        outlineColor="#000000"
      >
        EUROPE
      </Text>
    </group>
  );
};

client/src/components/VideoSection.tsx.content:
import { useRef, useState } from "react";
import { Play, Pause, SkipBack, SkipForward } from "lucide-react";
import Video from "../assets/video.mp4";
import VideoThumbnail from "../assets/thumnail.png";

const VideoSection = () => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [progress, setProgress] = useState(0); // for seek bar

  const handlePlay = () => {
    if (!videoRef.current) return;

    if (videoRef.current.paused) {
      videoRef.current.play();
      setIsPlaying(true);
    } else {
      videoRef.current.pause();
      setIsPlaying(false);
    }
  };

  const handleSkip = (sec: number) => {
    if (videoRef.current) {
      videoRef.current.currentTime += sec;
    }
  };

  const updateProgress = () => {
    if (videoRef.current) {
      const percentage =
        (videoRef.current.currentTime / videoRef.current.duration) * 100;
      setProgress(percentage);
    }
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = Number(e.target.value);
    const duration = videoRef.current?.duration || 0;
    if (videoRef.current) {
      videoRef.current.currentTime = (value / 100) * duration;
    }
    setProgress(value);
  };

  return (
    <section className="py-20 px-4 bg-gradient-to-br from-[hsl(var(--brand-blue))]/5 to-[hsl(var(--brand-green))]/5">
      <div className="max-w-6xl mx-auto">

        {/* Heading */}
        <div className="text-center mb-12">
          <h2 className="text-4xl md:text-5xl font-bold mb-4 bg-gradient-to-r from-[hsl(var(--brand-blue))] to-[hsl(var(--brand-green))] bg-clip-text text-transparent">
            See T-imoexo In Action
          </h2>
          <p className="text-lg text-muted-foreground max-w-2xl mx-auto">
            Discover how we simplify international trade for manufacturers, buyers, and sellers across the globe
          </p>
        </div>

        {/* Video Container */}
        <div className="relative rounded-2xl overflow-hidden shadow-2xl bg-gray-900 aspect-video max-w-3xl mx-auto">

          {/* VIDEO */}
          <video
            ref={videoRef}
            src={Video}
            poster={VideoThumbnail}
            className="w-full h-full object-cover"
            playsInline
            loop
            preload="metadata"
            onTimeUpdate={updateProgress}
          />

          {/* PLAY OVERLAY (no blur) */}
          {!isPlaying && (
            <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/40">

              {/* Play Button */}
              <button
                onClick={handlePlay}
                className="w-20 h-20 rounded-full bg-gradient-to-r from-[hsl(var(--brand-blue))] to-[hsl(var(--brand-green))] flex items-center justify-center shadow-xl hover:scale-110 transition-transform duration-300 animate-bounce"
              >
                <Play className="text-white ml-1" size={35} fill="white" />
              </button>

              {/* Restored Text */}
              <div className="text-center text-white mt-6">
                <h2 className="text-2xl font-bold mb-2 bg-gradient-to-r from-white to-gray-200 bg-clip-text text-transparent">
                  Company Overview Video
                </h2>
                <p className="text-sm sm:text-base bg-gradient-to-r from-gray-200 to-gray-300 bg-clip-text text-transparent">
                  Watch how T-imoexo connects businesses worldwide
                </p>
              </div>

              {/* Decorative circles */}
              <div className="absolute top-10 left-10 w-20 h-20 bg-[hsl(var(--brand-blue))]/10 rounded-full blur-xl" />
              <div className="absolute bottom-10 right-10 w-32 h-32 bg-[hsl(var(--brand-green))]/10 rounded-full blur-xl" />
            </div>
          )}

          {/* CONTROLS (visible when playing) */}
          {isPlaying && (
            <div className="absolute inset-0 flex flex-col justify-end pb-4 bg-gradient-to-t from-black/60 to-transparent">

              {/* SEEK BAR */}
              <input
                type="range"
                min="0"
                max="100"
                value={progress}
                onChange={handleSeek}
                className="w-full appearance-none h-2 bg-white/30 rounded-lg cursor-pointer accent-white mb-3"
              />

              {/* CONTROL BUTTONS */}
              <div className="flex items-center justify-center gap-6">
                {/* BACK 10s */}
                <button
                  onClick={() => handleSkip(-10)}
                  className="w-12 h-12 rounded-full bg-white/20 text-white flex items-center justify-center hover:bg-white/30 transition"
                >
                  <SkipBack size={20} />
                </button>

                {/* PAUSE BUTTON */}
                <button
                  onClick={handlePlay}
                  className="w-14 h-14 rounded-full bg-white/20 text-white flex items-center justify-center hover:bg-white/30 transition"
                >
                  <Pause size={22} />
                </button>

                {/* FORWARD 10s */}
                <button
                  onClick={() => handleSkip(10)}
                  className="w-12 h-12 rounded-full bg-white/20 text-white flex items-center justify-center hover:bg-white/30 transition"
                >
                  <SkipForward size={20} />
                </button>
              </div>
            </div>
          )}
        </div>
      </div>
    </section>
  );
};

export default VideoSection;

