import React, { useState } from 'react';
import { X, Send } from 'lucide-react';
import { FaWhatsapp } from 'react-icons/fa';

const FloatingChat = () => {
  const [isWhatsAppOpen, setIsWhatsAppOpen] = useState(false);

  // WhatsApp business number and welcome message
  const whatsappNumber = "+91 8237439036"; // Replace with actual business WhatsApp number
  const welcomeMessage = "Hi there! 👋\nWelcome to T-imoexo. How may we assist you today?";


  const handleWhatsAppClick = () => {
    if (isWhatsAppOpen) {
      // Close the preview
      setIsWhatsAppOpen(false);
    } else {
      // Show preview for 2 seconds then open WhatsApp
      setIsWhatsAppOpen(true);
      setTimeout(() => {
        setIsWhatsAppOpen(false);
        // Open WhatsApp with welcome message
        const encodedMessage = encodeURIComponent(welcomeMessage);
        const whatsappUrl = `https://wa.me/${whatsappNumber.replace(/[^0-9]/g, '')}?text=${encodedMessage}`;
        window.open(whatsappUrl, '_blank');
      }, 2000);
    }
  };

  return (
    <div className="fixed bottom-6 right-6 z-50">
      {/* WhatsApp Preview Window */}
      {isWhatsAppOpen && (
        <div className="bg-white rounded-2xl shadow-2xl border border-green-200 w-80 h-auto mb-4 overflow-hidden">
          {/* Header */}
          <div className="bg-gradient-to-r from-green-600 to-green-500 text-white p-4 flex items-center justify-between">
            <div className="flex items-center space-x-3">
              <div className="w-8 h-8 bg-white rounded-full flex items-center justify-center">
                <FaWhatsapp className="w-5 h-5 text-green-600" />
              </div>
              <div>
                <div className="font-bold text-sm">T-imoexo</div>
                <div className="text-xs text-green-100">Connect via WhatsApp</div>
              </div>
            </div>
            <button
              onClick={() => setIsWhatsAppOpen(false)}
              className="hover:bg-white/20 p-1 rounded"
              data-testid="button-close-whatsapp-preview"
            >
              <X className="w-5 h-5" />
            </button>
          </div>

          {/* Preview Message */}
          <div className="p-4">
            <div className="bg-green-50 rounded-xl p-3 border-l-4 border-green-500">
              <p className="text-sm text-gray-800 mb-2">
                <strong>Welcome Message Preview:</strong>
              </p>
              <p className="text-sm text-gray-700 whitespace-pre-line">
                {welcomeMessage}
              </p>
            </div>
            <div className="text-xs text-gray-500 mt-2 text-center">
              Opening WhatsApp in a moment...
            </div>
          </div>
        </div>
      )}

      {/* Floating WhatsApp Button */}
      <button
        onClick={handleWhatsAppClick}
        className="bg-gradient-to-r from-green-500 to-green-600 hover:from-green-600 hover:to-green-700 text-white p-4 rounded-full shadow-xl transition-all duration-300 transform hover:scale-110 relative group"
        data-testid="button-whatsapp-chat"
        title="Chat with us on WhatsApp"
      >
        {isWhatsAppOpen ? (
          <X className="w-6 h-6" />
        ) : (
          <>
            <FaWhatsapp className="w-6 h-6" />
            {/* Notification Dot */}
            <div className="absolute -top-1 -right-1 w-3 h-3 bg-red-400 rounded-full animate-pulse"></div>
            {/* Tooltip */}
            <div className="absolute bottom-full right-0 mb-2 px-3 py-1 bg-gray-800 text-white text-xs rounded-lg opacity-0 group-hover:opacity-100 transition-opacity duration-200 whitespace-nowrap">
              Chat on WhatsApp
            </div>
          </>
        )}
      </button>
    </div>
  );
};

export default FloatingChat;

client/src/admin/pages/InquiryDetail.tsx.content:
import { useState, useEffect } from 'react';
import { useParams, useNavigate, useSearchParams } from 'react-router-dom';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { ArrowLeft, Mail, Phone, MapPin, Building, Package, Calendar, User, MessageSquare } from 'lucide-react';
import { toast } from 'sonner';

interface InquiryData {
  id: number;
  name?: string;
  email: string;
  phone?: string;
  country?: string;
  requirements?: string;
  inquiry_type: 'buyer' | 'manufacturer' | 'contact';
  created_at: string;
  contact_person?: string;
  company_name?: string;
  product_category?: string;
  quantity?: string;
  production_capacity?: string;
  source_page?: string;
}

export const InquiryDetail = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();
  const inquiryType = searchParams.get('type') || '';

  const [inquiry, setInquiry] = useState<InquiryData | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    loadInquiry();
  }, [id, inquiryType]);

  const loadInquiry = async () => {
    try {
      setLoading(true);
      const url = inquiryType
        ? `/server/inquiries-admin.php?id=${id}&type=${inquiryType}`
        : `/server/inquiries-admin.php?id=${id}`;

      const response = await fetch(url, {
        credentials: 'include'
      });

      const result = await response.json();

      if (result.success) {
        setInquiry(result.data);
      } else {
        toast.error('Failed to load inquiry details');
        navigate('/admin/inquiries');
      }
    } catch (error) {
      toast.error('Error loading inquiry details');
      console.error(error);
      navigate('/admin/inquiries');
    } finally {
      setLoading(false);
    }
  };

  const getTypeLabel = (type: string) => {
    switch (type) {
      case 'buyer':
        return 'Buyer Inquiry';
      case 'manufacturer':
        return 'Manufacturer Inquiry';
      case 'contact':
        return 'Contact Inquiry';
      default:
        return type;
    }
  };

  const formatDate = (dateString: string) => {
    return new Date(dateString).toLocaleString('en-US', {
      year: 'numeric',
      month: 'long',
      day: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    });
  };

  if (loading) {
    return <div className="text-center py-12">Loading...</div>;
  }

  if (!inquiry) {
    return <div className="text-center py-12">Inquiry not found</div>;
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center gap-4">
        <Button
          variant="ghost"
          size="icon"
          onClick={() => navigate('/admin/inquiries')}
        >
          <ArrowLeft className="h-5 w-5" />
        </Button>
        <div>
          <h1 className="text-2xl font-bold text-gray-900">Inquiry Details</h1>
          <p className="text-gray-500 mt-1">{getTypeLabel(inquiry.inquiry_type)}</p>
        </div>
      </div>

      <Card>
        <CardHeader>
          <div className="flex items-center justify-between">
            <CardTitle>Contact Information</CardTitle>
            <span className={`px-3 py-1 rounded-full text-sm font-medium ${inquiry.inquiry_type === 'buyer'
              ? 'bg-blue-100 text-blue-700'
              : inquiry.inquiry_type === 'manufacturer'
                ? 'bg-green-100 text-green-700'
                : 'bg-purple-100 text-purple-700'
              }`}>
              {getTypeLabel(inquiry.inquiry_type)}
            </span>
          </div>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {inquiry.name && (
              <div className="flex items-start gap-3">
                <User className="h-5 w-5 text-gray-400 mt-0.5" />
                <div>
                  <p className="text-sm text-gray-500">Name</p>
                  <p className="font-medium text-gray-900">{inquiry.name}</p>
                </div>
              </div>
            )}

            {inquiry.contact_person && (
              <div className="flex items-start gap-3">
                <User className="h-5 w-5 text-gray-400 mt-0.5" />
                <div>
                  <p className="text-sm text-gray-500">Contact Person</p>
                  <p className="font-medium text-gray-900">{inquiry.contact_person}</p>
                </div>
              </div>
            )}

            {inquiry.company_name && (
              <div className="flex items-start gap-3">
                <Building className="h-5 w-5 text-gray-400 mt-0.5" />
                <div>
                  <p className="text-sm text-gray-500">Company Name</p>
                  <p className="font-medium text-gray-900">{inquiry.company_name}</p>
                </div>
              </div>
            )}

            <div className="flex items-start gap-3">
              <Mail className="h-5 w-5 text-gray-400 mt-0.5" />
              <div>
                <p className="text-sm text-gray-500">Email</p>
                <a
                  href={`mailto:${inquiry.email}`}
                  className="font-medium text-blue-600 hover:underline"
                >
                  {inquiry.email}
                </a>
              </div>
            </div>

            {inquiry.phone && (
              <div className="flex items-start gap-3">
                <Phone className="h-5 w-5 text-gray-400 mt-0.5" />
                <div>
                  <p className="text-sm text-gray-500">Phone</p>
                  <a
                    href={`tel:${inquiry.phone}`}
                    className="font-medium text-blue-600 hover:underline"
                  >
                    {inquiry.phone}
                  </a>
                </div>
              </div>
            )}

            {inquiry.country && (
              <div className="flex items-start gap-3">
                <MapPin className="h-5 w-5 text-gray-400 mt-0.5" />
                <div>
                  <p className="text-sm text-gray-500">Country</p>
                  <p className="font-medium text-gray-900">{inquiry.country}</p>
                </div>
              </div>
            )}

            <div className="flex items-start gap-3">
              <Calendar className="h-5 w-5 text-gray-400 mt-0.5" />
              <div>
                <p className="text-sm text-gray-500">Submitted At</p>
                <p className="font-medium text-gray-900">{formatDate(inquiry.created_at)}</p>
              </div>
            </div>

            {inquiry.product_category && (
              <div className="flex items-start gap-3">
                <Package className="h-5 w-5 text-gray-400 mt-0.5" />
                <div>
                  <p className="text-sm text-gray-500">Product Category</p>
                  <p className="font-medium text-gray-900">{inquiry.product_category}</p>
                </div>
              </div>
            )}

            {inquiry.quantity && (
              <div className="flex items-start gap-3">
                <Package className="h-5 w-5 text-gray-400 mt-0.5" />
                <div>
                  <p className="text-sm text-gray-500">Quantity</p>
                  <p className="font-medium text-gray-900">{inquiry.quantity}</p>
                </div>
              </div>
            )}

            {inquiry.production_capacity && (
              <div className="flex items-start gap-3">
                <Package className="h-5 w-5 text-gray-400 mt-0.5" />
                <div>
                  <p className="text-sm text-gray-500">Production Capacity</p>
                  <p className="font-medium text-gray-900">{inquiry.production_capacity}</p>
                </div>
              </div>
            )}

            {inquiry.source_page && (
              <div className="flex items-start gap-3">
                <Package className="h-5 w-5 text-gray-400 mt-0.5" />
                <div>
                  <p className="text-sm text-gray-500">Source Page</p>
                  <p className="font-medium text-gray-900">{inquiry.source_page}</p>
                </div>
              </div>
            )}

            {inquiry.requirements && (
              <div className="flex items-start gap-3 md:col-span-2">
                <MessageSquare className="h-5 w-5 text-gray-400 mt-0.5" />
                <div className="flex-1">
                  <p className="text-sm text-gray-500">Message / Requirements</p>
                  <p className="font-medium text-gray-900 whitespace-pre-wrap">{inquiry.requirements.replace(/&#039;/g, "'")}</p>
                </div>
              </div>
            )}
          </div>
        </CardContent>
      </Card>
    </div>
  );
};

client/src/admin/pages/Inquiries.tsx.content:
import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { Card, CardContent } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { 
  Search,
  Inbox,
  Download
} from 'lucide-react';
import { toast } from 'sonner';
import * as XLSX from 'xlsx';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";

interface Inquiry {
  id: number;
  name: string;
  email: string;
  phone: string;
  country: string;
  requirements: string;
  inquiry_type: 'buyer' | 'manufacturer' | 'contact';
  type_label: string;
  created_at: string;
  contact_person?: string;
  company_name?: string;
  product_category?: string;
  quantity?: string;
  production_capacity?: string;
  source_page?: string;
}

export const Inquiries = () => {
  const navigate = useNavigate();
  const [inquiries, setInquiries] = useState<Inquiry[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [filterType, setFilterType] = useState<string>('all');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    loadInquiries();
  }, [filterType]);

  const loadInquiries = async () => {
    try {
      setLoading(true);
      const response = await fetch(`/server/inquiries-admin.php?filter=${filterType}`, {
        credentials: 'include'
      });

      const result = await response.json();

      if (result.success) {
        setInquiries(result.data);
      } else {
        toast.error('Failed to load inquiries');
      }
    } catch (error) {
      toast.error('Error loading inquiries');
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const filteredInquiries = inquiries.filter(inquiry => {
    const searchLower = searchQuery.toLowerCase();
    const name = inquiry.name?.toLowerCase() || '';
    const email = inquiry.email?.toLowerCase() || '';
    const phone = inquiry.phone?.toLowerCase() || '';
    const typeLabel = inquiry.type_label?.toLowerCase() || '';

    return name.includes(searchLower) || 
           email.includes(searchLower) || 
           phone.includes(searchLower) || 
           typeLabel.includes(searchLower);
  });

  const handleInquiryClick = (inquiry: Inquiry) => {
    navigate(`/admin/inquiries/${inquiry.id}?type=${inquiry.inquiry_type}`);
  };

  const exportToExcel = () => {
    try {
      const exportData = filteredInquiries.map(inquiry => ({
        'ID': inquiry.id,
        'Name': inquiry.name,
        'Email': inquiry.email,
        'Phone': inquiry.phone,
        'Country': inquiry.country,
        'Company Name': inquiry.company_name || 'N/A',
        'Contact Person': inquiry.contact_person || 'N/A',
        'Product Category': inquiry.product_category || 'N/A',
        'Quantity': inquiry.quantity || 'N/A',
        'Production Capacity': inquiry.production_capacity || 'N/A',
        'Requirements/Message': inquiry.requirements,
        'Inquiry Type': inquiry.type_label,
        'Source Page': inquiry.source_page || 'N/A',
        'Date': new Date(inquiry.created_at).toLocaleDateString()
      }));

      const ws = XLSX.utils.json_to_sheet(exportData);
      const wb = XLSX.utils.book_new();
      XLSX.utils.book_append_sheet(wb, ws, 'Inquiries');

      const colWidths = [
        { wch: 6 },
        { wch: 20 },
        { wch: 25 },
        { wch: 15 },
        { wch: 15 },
        { wch: 20 },
        { wch: 20 },
        { wch: 20 },
        { wch: 15 },
        { wch: 20 },
        { wch: 40 },
        { wch: 18 },
        { wch: 15 },
        { wch: 12 }
      ];
      ws['!cols'] = colWidths;

      const fileName = `inquiries_${filterType}_${new Date().toISOString().split('T')[0]}.xlsx`;
      XLSX.writeFile(wb, fileName);

      toast.success(`Exported ${exportData.length} inquiries to Excel`);
    } catch (error) {
      console.error('Export error:', error);
      toast.error('Failed to export inquiries');
    }
  };

  if (loading) {
    return <div className="text-center py-12">Loading...</div>;
  }

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-2xl font-bold text-gray-900">Inquiries</h1>
        <p className="text-gray-500 mt-1">Manage all customer inquiries and submissions</p>
      </div>

      <div className="flex flex-col sm:flex-row gap-4">
        <Select value={filterType} onValueChange={setFilterType}>
          <SelectTrigger className="w-full sm:w-[200px]">
            <SelectValue placeholder="Filter by type" />
          </SelectTrigger>

          <SelectContent className="bg-white">
            <SelectItem value="all">All Inquiries</SelectItem>
            <SelectItem value="buyer">Buyer Inquiry</SelectItem>
            <SelectItem value="manufacturer">Manufacturer Inquiry</SelectItem>
            <SelectItem value="contact">Contact Inquiry</SelectItem>
          </SelectContent>
        </Select>


        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400 h-4 w-4" />
          <Input
            type="text"
            placeholder="Search by name, email, phone, or type..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="pl-10"
          />
        </div>

        <Button
          onClick={exportToExcel}
          variant="outline"
          className="sm:w-auto w-full flex items-center gap-2"
          disabled={filteredInquiries.length === 0}
        >
          <Download className="h-4 w-4" />
          Export to Excel
        </Button>
      </div>

      {filteredInquiries.length === 0 ? (
        <Card>
          <CardContent className="py-12">
            <div className="text-center">
              <Inbox className="mx-auto h-12 w-12 text-gray-400 mb-4" />
              <h3 className="text-lg font-medium text-gray-900 mb-2">No Inquiries Found</h3>
              <p className="text-gray-500">
                {searchQuery ? 'Try adjusting your search terms' : 'No inquiries have been submitted yet'}
              </p>
            </div>
          </CardContent>
        </Card>
      ) : (
        <Card>
          <CardContent className="p-0">
            <div className="divide-y divide-gray-200">
              {filteredInquiries.map((inquiry) => (
                <div
                  key={`${inquiry.inquiry_type}-${inquiry.id}`}
                  onClick={() => handleInquiryClick(inquiry)}
                  className="flex items-center justify-between p-4 hover:bg-gray-50 cursor-pointer transition-colors"
                >
                  <div className="flex-1">
                    <p className="font-medium text-gray-900">{inquiry.name}</p>
                  </div>
                  <div className="flex items-center gap-2">
                    <span className={`px-3 py-1 rounded-full text-sm font-medium ${
                      inquiry.inquiry_type === 'buyer' 
                        ? 'bg-blue-100 text-blue-700'
                        : inquiry.inquiry_type === 'manufacturer'
                        ? 'bg-green-100 text-green-700'
                        : 'bg-purple-100 text-purple-700'
                    }`}>
                      {inquiry.type_label}
                    </span>
                  </div>
                </div>
              ))}
            </div>
          </CardContent>
        </Card>
      )}

      <div className="text-sm text-gray-500 text-center">
        Showing {filteredInquiries.length} of {inquiries.length} inquiries
      </div>
    </div>
  );
};

